  @state SLOT_KEY_W, SLOT_KIND_W = 18, 16  @ 40
  @state openCreateModal  @ 43
  @state press = nil  @ 49
      @invariant  drag relocates via am:startIsClear; cursor moves only on clean (no-drag) release.
      @invariant  gutter press drives REAPER transport — release sets edit cursor, drag sets loop range.
      @invariant  double-click on empty space starts a create press; release opens create modal.
  @state WHEEL_STEP_ROWS = 1  @ 50   -- cursor rows moved per mouse-wheel notch
  @state WHEEL_STEP_COLS = 0.5  @ 51   -- cursor cols moved per mouse-wheel notch
  @state wheelAccumV = 0  @ 52   -- fractional vertical wheel carried between frames
